function loadAnnouncement(){$.get("/announcement.json?t="+(new Date).getTime(),function(n,t,e){$(".non-js").hide(),"success"===t?(n.map(function(n){return n.time=dateFormat("YYYY-mm-dd HH:MM",new Date(n.time)),n}),new Vue({el:"#app",data:{announcements:n}})):$("#failed").text("加载公告失败！Loading announcement failed!")},"json")}function dateFormat(n,t){var e=null,o={"Y+":t.getFullYear().toString(),"m+":(t.getMonth()+1).toString(),"d+":t.getDate().toString(),"H+":t.getHours().toString(),"M+":t.getMinutes().toString(),"S+":t.getSeconds().toString()};for(var a in o)(e=new RegExp("("+a+")").exec(n))&&(n=n.replace(e[1],1===e[1].length?o[a]:o[a].padStart(e[1].length,"0")));return n}loadAnnouncement();